1	export class ShippingError extends Error {
2	  constructor(public readonly code: string, message: string) {
3	    super(message);
4	    this.name = "ShippingError";
5	  }
6	}
7	
8	const RATES: Record<string, number> = {
9	  domestic: 2.5,
10	  international: 7.5,
11	  express_domestic: 4.0,
12	  freight: 1.5,
13	};
14	
15	export function calculateShipping(weight: number, destination: string): number {
16	  if (!(destination in RATES)) {
17	    throw new ShippingError(
18	      "UNKNOWN_DESTINATION",
19	      `Unknown destination: "${destination}"`
20	    );
21	  }
22	
23	  if (weight <= 0) {
24	    throw new ShippingError(
25	      "INVALID_WEIGHT",
26	      `Weight must be positive, got: ${weight}`
27	    );
28	  }
29	
30	  return weight * RATES[destination];
31	}
